import json

def parse(text):
    try:
        data = json.loads(text)
    except json.JSONDecodeError as e:
        print(f"bad json: {e}")
        return {}
    else:
        return data          # only runs if no exception
    finally:
        print("parse attempt done")   # always runs

print(parse('{"ok": true}'))   # {'ok': True}
print(parse('not json'))        # {}

def get_temperature(config):
    try:
        return float(config["temperature"])
    except KeyError:
        return 0.7                      # missing -> default
    except (TypeError, ValueError):
        return 0.7                      # wrong type/format -> default

print(get_temperature({"temperature": "0.2"}))   # 0.2
print(get_temperature({}))                         # 0.7

class ToolError(Exception):
    """Raised when an LLM tool call fails."""

def call_tool(name):
    try:
        raise OSError("network down")
    except OSError as e:
        raise ToolError(f"tool {name} failed") from e   # keep the cause

try:
    call_tool("search")
except ToolError as e:
    print(e)            # tool search failed
    print(e.__cause__)  # network down  (original exception preserved)

import time

class RateLimitError(Exception):
    pass

def with_retry(fn, attempts=3):
    for i in range(1, attempts + 1):
        try:
            return fn()
        except (RateLimitError, TimeoutError) as e:
            if i == attempts:
                raise                 # give up: re-raise the last error
            time.sleep(2 ** i)        # back off, then retry
            print(f"retry {i}: {e}")
